#!/usr/bin/env node
/**
 * Creates minimal stubs for files that are gitignored (generated by Convex
 * codegen) so that tests can import server modules without a live Convex
 * deployment.  Safe to re-run; it is idempotent.
 */
import { mkdirSync, writeFileSync, existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const generatedDir = resolve(root, "convex/_generated");

mkdirSync(generatedDir, { recursive: true });

const apiStub = resolve(generatedDir, "api.js");
if (!existsSync(apiStub)) {
  writeFileSync(
    apiStub,
    `// Minimal stub for test environments where Convex codegen has not run.
export const api = new Proxy(
  {},
  {
    get(_target, ns) {
      return new Proxy(
        {},
        {
          get(_t, fn) {
            return String(ns) + ":" + String(fn);
          },
        },
      );
    },
  },
);
`,
  );
  console.log("[test-stubs] created convex/_generated/api.js stub");
}
